<?php
namespace App\Modules\Hr\Training\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use App\Modules\Hr\Training\Models\HrTrainingEnrollment; use App\Modules\Hr\Training\Models\HrTrainingSession; use Illuminate\Support\Facades\DB;
class EnrollTrainingEmployeeAction { public function __construct(private HrAuditService $audit){} public function execute(HrTrainingSession $session,HrEmployee $employee):HrTrainingEnrollment{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.training.enroll'),403);abort_unless($session->legal_entity_id===$tenant&&$employee->legal_entity_id===$tenant,404);return DB::transaction(function()use($session,$employee,$tenant){$locked=HrTrainingSession::withoutGlobalScope('tenant')->whereKey($session->id)->lockForUpdate()->firstOrFail();abort_unless($locked->status==='scheduled',422,'Yalnızca planlanmış oturuma kayıt yapılabilir.');$existing=HrTrainingEnrollment::withoutGlobalScope('tenant')->where('session_id',$locked->id)->where('employee_id',$employee->id)->first();if($existing)return $existing;if($locked->capacity!==null)abort_if(HrTrainingEnrollment::withoutGlobalScope('tenant')->where('session_id',$locked->id)->whereNotIn('status',['cancelled'])->count()>=$locked->capacity,422,'Eğitim kontenjanı dolu.');$row=HrTrainingEnrollment::create(['legal_entity_id'=>$tenant,'session_id'=>$locked->id,'employee_id'=>$employee->id,'status'=>'enrolled','progress_percent'=>0,'enrolled_by'=>auth()->id()]);$this->audit->log('training_employee_enrolled',$row);return $row;});} }
